const seq = [38,38,40,40,37,39,37,39,66,65];
let buffer = [];
let overlay = null;
let egg = null;
const eggImage = "data:image/png;base64,";

function showEgg() {
  if (!overlay) {
    overlay = document.createElement("div");
    overlay.id = "egg-overlay";
    document.body.appendChild(overlay);
  }
  if (!egg) {
    egg = document.createElement("img");
    egg.id = "egg";
    egg.src = eggImage;
    document.body.appendChild(egg);
  }

  requestAnimationFrame(() => {
    overlay.classList.add("active");
    egg.classList.add("active");
  });

  window.addEventListener("click", hideEgg, { once: true });
}

function hideEgg() {
 if (egg) egg.classList.remove("active");
 if (overlay) overlay.classList.remove("active");
}

window.addEventListener("keydown", (e) => {
  const code = e.keyCode || e.which;

  buffer.push(code);
  if (buffer.length > seq.length) buffer.shift();

  let match = true;
  for (let i = 0; i < seq.length; i++) {
    if (buffer[i] !== seq[i]) {
      match = false;
      break;
    }
  }

  if (match) {
    showEgg();
  }
});
